operations.command:
gh api graphql -f query='
query {
  organization(login: "gptcompany") {
    projectV2(number: 14) {
      title
      items(first: 20) {
        totalCount
        nodes {
          content {
            ... on Issue {
              title
              state
            }
          }
        }
      }
    }
  }
}' 2>&1 | head -50

gh api graphql -f query='
query {
  organization(login: "gptcompany") {
    projectV2(number: 14) {
      title
      items(first: 40) {
        totalCount
        nodes {
          content {
            ... on Issue {
              title
              state
              number
            }
          }
        }
      }
    }
  }
}' 2>&1 | jq -r '.data.organization.projectV2.items.nodes[].content | select(.title != null) | "\(.state) #\(.number): \(.title)"' | grep -E "(03-|05-05)" | head -10

